mapper.select:
SELECT 
  o.*, 
  p.product_name AS product_name, 
  c.client_name AS client_name     
FROM product_outbound o
LEFT JOIN product p ON o.product_id = p.product_id
LEFT JOIN client c ON o.client_id = c.client_id


    (
      p.product_name LIKE CONCAT('%', #{keyword}, '%') OR
      o.product_id LIKE CONCAT('%', #{keyword}, '%') OR
      o.lot_no LIKE CONCAT('%', #{keyword}, '%') OR
      c.client_name LIKE CONCAT('%', #{keyword}, '%')
    )

   AND DATE(o.outbound_date) >= #{startDate} 
   AND DATE(o.outbound_date) <= #{endDate} 




    ORDER BY p.product_name ${sortOrder}


    ORDER BY o.lot_no ${sortOrder}


    ORDER BY o.outbound_date ${sortOrder}


    ORDER BY c.client_name ${sortOrder}


    ORDER BY o.manager ${sortOrder}


    ORDER BY o.outbound_date DESC



LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM product_outbound o LEFT JOIN product p ON o.product_id = p.product_id LEFT JOIN client c ON o.client_id = c.client_id
( p.product_name LIKE CONCAT('%', #{keyword}, '%') OR o.product_id LIKE CONCAT('%', #{keyword}, '%') OR o.lot_no LIKE CONCAT('%', #{keyword}, '%') OR c.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND DATE(o.outbound_date) >= #{startDate} AND DATE(o.outbound_date) <= #{endDate}

